// Use OpenZeppelin Initializable and lock the implementation.
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

contract Vault is Initializable, OwnableUpgradeable {
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers(); // block init on the implementation
    }

    function initialize(address owner_) external initializer {
        __Ownable_init(owner_); // runs exactly once on the proxy
    }
}

// Ensure the deploy script calls initialize atomically with the proxy deploy.
